{
	return net_generic(net, synproxy_net_id);
}

struct synproxy_options {
	u8				options;
	u8				wscale;
	u16				mss_option;
	u16				mss_encode;
	u32				tsval;
	u32				tsecr;
};

struct nf_synproxy_info;
